// ---- ViewModel with Compose Patterns ----

// ---- User data class ----
data class User(
    val id: Int,
    val name: String,
    val email: String,
    val isActive: Boolean
)

// ---- UI State ----
data class UserUiState(
    val users: List<User> = emptyList(),
    val isLoading: Boolean = false,
    val error: String? = null,
    val selectedUser: User? = null
)

// ---- User ViewModel ----
class UserViewModel : ViewModel() {
    // ---- Single state object ----
    private val _uiState = MutableStateFlow(UserUiState())
    val uiState: StateFlow<UserUiState> = _uiState.asStateFlow()

    // ---- Load users ----
    fun loadUsers() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }

            try {
                // Simulate network call
                delay(1500)
                val users = listOf(
                    User(1, "Hero", "hero@example.com", true),
                    User(2, "Aragorn", "aragorn@example.com", true),
                    User(3, "Gandalf", "gandalf@example.com", false)
                )
                _uiState.update { it.copy(
                    users = users,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Unknown error",
                    isLoading = false
                )}
            }
        }
    }

    // ---- Select user ----
    fun selectUser(user: User) {
        _uiState.update { it.copy(selectedUser = user) }
    }

    // ---- Add user ----
    fun addUser(name: String, email: String) {
        val newUser = User(
            id = (_uiState.value.users.maxOfOrNull { it.id } ?: 0) + 1,
            name = name,
            email = email,
            isActive = true
        )
        _uiState.update { it.copy(
            users = it.users + newUser
        )}
    }

    // ---- Toggle user active ----
    fun toggleUserActive(userId: Int) {
        _uiState.update { state ->
            val updatedUsers = state.users.map { user ->
                if (user.id == userId) {
                    user.copy(isActive = !user.isActive)
                } else {
                    user
                }
            }
            state.copy(users = updatedUsers)
        }
    }

    // ---- Clear error ----
    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- User Screen ----
@Composable
fun UserScreen() {
    val viewModel: UserViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()

    Scaffold(
        topBar = {
            TopAppBar {
                Text("Users")
            }
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp)
        ) {
            // ---- Loading state ----
            if (uiState.isLoading) {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator()
                }
                return@Column
            }

            // ---- Error state ----
            if (uiState.error != null) {
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 16.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "Error: ${uiState.error}",
                            color = MaterialTheme.colorScheme.onErrorContainer
                        )
                        Button(
                            onClick = { viewModel.clearError() }
                        ) {
                            Text("Dismiss")
                        }
                    }
                }
            }

            // ---- Add user ----
            var name by remember { mutableStateOf("") }
            var email by remember { mutableStateOf("") }

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                OutlinedTextField(
                    value = name,
                    onValueChange = { name = it },
                    label = { Text("Name") },
                    modifier = Modifier.weight(1f)
                )
                OutlinedTextField(
                    value = email,
                    onValueChange = { email = it },
                    label = { Text("Email") },
                    modifier = Modifier.weight(1f)
                )
                Button(
                    onClick = {
                        if (name.isNotBlank() && email.isNotBlank()) {
                            viewModel.addUser(name, email)
                            name = ""
                            email = ""
                        }
                    },
                    modifier = Modifier.align(Alignment.Bottom)
                ) {
                    Text("Add")
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            // ---- User list ----
            LazyColumn(
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(uiState.users) { user ->
                    UserCard(
                        user = user,
                        onSelect = { viewModel.selectUser(it) },
                        onToggleActive = { viewModel.toggleUserActive(it) }
                    )
                }
            }

            // ---- Selected user ----
            if (uiState.selectedUser != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "Selected: ${uiState.selectedUser?.name}",
                            style = MaterialTheme.typography.titleMedium
                        )
                        Text(
                            text = uiState.selectedUser?.email ?: ""
                        )
                    }
                }
            }

            // ---- Load button ----
            Button(
                onClick = { viewModel.loadUsers() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Reload")
            }
        }
    }
}

// ---- User Card ----
@Composable
fun UserCard(
    user: User,
    onSelect: (User) -> Unit,
    onToggleActive: (Int) -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onSelect(user) },
        elevation = CardDefaults.cardElevation(2.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = user.name,
                    style = MaterialTheme.typography.titleMedium
                )
                Text(
                    text = user.email,
                    style = MaterialTheme.typography.bodyMedium
                )
            }

            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                // Active indicator
                Box(
                    modifier = Modifier
                        .size(12.dp)
                        .background(
                            if (user.isActive) Color.Green else Color.Red,
                            CircleShape
                        )
                )

                Button(
                    onClick = { onToggleActive(user.id) }
                ) {
                    Text(if (user.isActive) "Deactivate" else "Activate")
                }
            }
        }
    }
}

