package com.example.uistate

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.viewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update

data class UiState(
    val count: Int = 0,
    val message: String = "Hello"
)

class UiStateViewModel : ViewModel() {
    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun increment() {
        _uiState.update { it.copy(count = it.count + 1) }
    }

    fun updateMessage(newMessage: String) {
        _uiState.update { it.copy(message = newMessage) }
    }
}

@Composable
fun UiStateApp() {
    val viewModel: UiStateViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()

    var input by remember { mutableStateOf("") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Text(
            text = "Count: ${uiState.count}",
            style = MaterialTheme.typography.headlineLarge
        )

        Text(
            text = "Message: ${uiState.message}",
            style = MaterialTheme.typography.titleLarge
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = { viewModel.increment() }) {
                Text("+")
            }
        }

        OutlinedTextField(
            value = input,
            onValueChange = { input = it },
            label = { Text("New Message") },
            modifier = Modifier.fillMaxWidth()
        )

        Button(
            onClick = {
                if (input.isNotBlank()) {
                    viewModel.updateMessage(input)
                    input = ""
                }
            },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Update Message")
        }
    }
}
